class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

def deleteNode(head, node=None):
    def list_to_linked(arr):
        if not arr:
            return None, None
        head = ListNode(arr[0])
        curr = head
        target_node = None
        for i, val in enumerate(arr[1:], 1):
            curr.next = ListNode(val)
            curr = curr.next
            if val == node:
                target_node = curr
        if arr[0] == node:
            target_node = head
        return head, target_node

    def linked_to_list(head):
        result = []
        while head:
            result.append(head.val)
            head = head.next
        return result

    if isinstance(head, list):
        head, node_to_delete = list_to_linked(head)
        node = node_to_delete

    if node and node.next:
        node.val = node.next.val
        node.next = node.next.next

    return linked_to_list(head)

